import json, re, pandas as pd

path = var_call_7sYTgIMETxVgLty3pAik9qLu
with open(path,'r') as f:
    biz = json.load(f)

def state_from_desc(desc):
    if not desc:
        return None
    m = re.search(r',\s*([A-Z]{2})\b', desc)
    return m.group(1) if m else None

rows=[]
for r in biz:
    state = r.get('state') or state_from_desc(r.get('description'))
    rc = None
    try:
        rc=int(r.get('review_count'))
    except Exception:
        pass
    rows.append({'state':state,'review_count':rc})

df=pd.DataFrame(rows)
df2=df.dropna(subset=['state','review_count'])
if df2.empty:
    out={'error':'Could not extract any state values from business description/state fields.'}
else:
    s = df2.groupby('state')['review_count'].sum().sort_values(ascending=False)
    out={'top_state':s.index[0],'total_reviews':int(s.iloc[0]),'states_found':int(df2['state'].nunique()),'businesses_with_state':int(len(df2))}
print('__RESULT__:')
print(json.dumps(out))

